import { d3_arc } from "../../../core/d3-constants";
import { getMarkValue } from '../../parser/parser-helpers';

function arcMark(config, cache){
    return {
        config: {
            d: function(d, i){
                let node = this,
                    args = [d, i],
                    newConfig = config.d ? getMarkValue(node, args, config, 'd', cache) : config;

                    let innerRadius = getMarkValue(node, args, newConfig, "innerRadius", cache),
                    outerRadius = getMarkValue(node, args, newConfig, "outerRadius", cache),
                    startAngle = getMarkValue(node, args, newConfig, "startAngle", cache),
                    endAngle = getMarkValue(node, args, newConfig, "endAngle", cache),
                    cornerRadius = getMarkValue(node, args, newConfig, 'cornerRadius', cache),
                    padAngle = getMarkValue(node, args, newConfig, "padAngle", cache),
                    
                    arc = d3_arc()
                            .innerRadius(innerRadius)
                            .outerRadius(outerRadius)
                            .startAngle(startAngle)
                            .endAngle(endAngle)
                            .cornerRadius(cornerRadius)
                            .padAngle(padAngle);

                    return arc(d);
                
            }
        },
        depends: {
            d: ['innerRadius', 'outerRadius', 'startAngle', 'endAngle', 'cornerRadius']
        }
    }
}

export { arcMark };